#include <bits/stdc++.h>
using namespace std;
long long a,k;
int main() {
	cin>>a>>k;
	if(a/1000%k) {
		cout<<a/1000%k;
		cout<<a/100%10%k;
		cout<<a/10%10%k;
		cout<<a%10%k;
	}else if(a/100%10%k){
		cout<<a/100%10%k;
		cout<<a/10%10%k;
		cout<<a%10%k;
	}else if(a/10%10%k){
		cout<<a/10%10%k;
		cout<<a%10%k;
	}else{
		cout<<a%10%k;
	}
	return 0;
}
